    (key: string, partial: Partial<LogEntry>, options?: { remove?: boolean }) => {
      const existing = log[key];
      const merged: Partial<LogEntry> = { ...existing, ...partial };

      for (const k of Object.keys(merged) as (keyof LogEntry)[]) {
