      }

      const meaningless =
        options?.remove ||
        (!merged.weight &&
          !merged.difficulty &&
          !merged.notes &&
          !merged.completed);

      if (meaningless) {
        setLog((prev) => {
          if (!(key in prev)) return prev;
          const next = { ...prev };
          delete next[key];
          return next;
        });
        deleteLogEntry(key).catch(() => {});
